package org.apache.commons.math.optimization.general;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "classpath:org/apache/commons/math/optimization/general/requirement.feature"
)
public class CucumberTest {
    // JUnit runner for Cucumber tests
}

package org.apache.commons.math.optimization.general.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math.optimization.general.LevenbergMarquardtOptimizer;
import org.apache.commons.math.optimization.VectorialPointValuePair;
import org.apache.commons.math.FunctionEvaluationException;
import org.apache.commons.math.optimization.OptimizationException;

import java.util.Map;

import static org.junit.Assert.*;

public class StepDefs {

    private LevenbergMarquardtOptimizer optimizer;
    private double[] startPoint;
    private double[] expectedParameters;
    private double parameterAbsoluteErrorTolerance;
    private VectorialPointValuePair result;
    private Exception exception;

    // JennrichSampsonFunction implementation
    public static class JennrichSampsonFunction implements
            org.apache.commons.math.analysis.DifferentiableMultivariateVectorialFunction {

        private final int m;
        private final double[] startParams;

        public JennrichSampsonFunction(int m, double[] startParams) {
            this.m = m;
            this.startParams = startParams;
        }

        @Override
        public double[] value(double[] variables) {
            double x1 = variables[0];
            double x2 = variables[1];
            double[] f = new double[m];
            for (int i = 0; i < m; ++i) {
                double temp = i + 1;
                f[i] = 2 + 2 * temp - Math.exp(temp * x1) - Math.exp(temp * x2);
            }
            return f;
        }

        @Override
        public org.apache.commons.math.analysis.MultivariateMatrixFunction jacobian() {
            return new org.apache.commons.math.analysis.MultivariateMatrixFunction() {
                @Override
                public double[][] value(double[] variables) {
                    return jacobian(variables);
                }
            };
        }

        public double[][] jacobian(double[] variables) {
            double x1 = variables[0];
            double x2 = variables[1];
            double[][] jacobian = new double[m][];
            for (int i = 0; i < m; ++i) {
                double t = i + 1;
                jacobian[i] = new double[] { -t * Math.exp(t * x1), -t * Math.exp(t * x2) };
            }
            return jacobian;
        }

        public double[] getStartPoint() {
            return this.startParams.clone();
        }

        public double[] getTarget() {
            return new double[m]; // All zeros
        }

        public double[] getWeight() {
            double[] weights = new double[m];
            for (int i = 0; i < m; ++i) {
                weights[i] = 1.0;
            }
            return weights;
        }
    }

    @Given("^the Levenberg-Marquardt optimizer configured with:$")
    public void the_Levenberg_Marquardt_optimizer_configured_with(Map<String, String> config) {
        optimizer = new LevenbergMarquardtOptimizer();

        for (Map.Entry<String, String> entry : config.entrySet()) {
            String key = entry.getKey();
            double value = Double.parseDouble(entry.getValue());
            switch (key) {
                case "cost relative tolerance":
                    optimizer.setCostRelativeTolerance(value);
                    break;
                case "parameters relative tolerance":
                    optimizer.setParRelativeTolerance(value);
                    break;
                case "orthogonality tolerance":
                    optimizer.setOrthoTolerance(value);
                    break;
                default:
                    throw new IllegalArgumentException("Unknown configuration parameter: " + key);
            }
        }
        optimizer.setMaxIterations(100 * (2 + 1)); // Standard setting based on function
    }

    @Given("^the Jennrich-Sampson function with start point:$")
    public void the_Jennrich_Sampson_function_with_start_point(io.cucumber.datatable.DataTable dataTable) {
        java.util.List<java.util.List<String>> rows = dataTable.asLists();
        startPoint = new double[2];
        startPoint[0] = Double.parseDouble(rows.get(0).get(0));  // 0.3
        startPoint[1] = Double.parseDouble(rows.get(1).get(0));  // 0.4
    }

    @When("^the optimizer minimizes the function$")
    public void the_optimizer_minimizes_the_function() {
        try {
            JennrichSampsonFunction function = new JennrichSampsonFunction(10, startPoint);
            result = optimizer.optimize(function, function.getTarget(), function.getWeight(), function.getStartPoint());
        } catch (FunctionEvaluationException | OptimizationException e) {
            exception = e;
        }
    }

    @Then("^the resulting parameters should be approximately:$")
    public void the_resulting_parameters_should_be_approximately(io.cucumber.datatable.DataTable dataTable) {
        if (exception != null) {
            throw new AssertionError("Optimization failed with exception: " + exception.getMessage());
        }

        java.util.List<java.util.List<String>> rows = dataTable.asLists();
        expectedParameters = new double[2];
        expectedParameters[0] = Double.parseDouble(rows.get(0).get(0));  // 0.2578199266
        expectedParameters[1] = Double.parseDouble(rows.get(1).get(0));  // 0.2578299768

        double[] resultParams = result.getPoint();

        assertEquals("Parameter 1 should match expected", expectedParameters[0], resultParams[0], parameterAbsoluteErrorTolerance);
        assertEquals("Parameter 2 should match expected", expectedParameters[1], resultParams[1], parameterAbsoluteErrorTolerance);
    }

    @Then("^the parameter absolute error tolerance should be within (\\d+\\.\\d+E-\\d+)$")
    public void the_parameter_absolute_error_tolerance_should_be_within(double tolerance) {
        parameterAbsoluteErrorTolerance = tolerance;
    }
}

